Query.Sql:
with ct as ( select distinct Record ->> '$.LinkagePatientId.NhsNumber.@extension' as NhsNumber,
unnest ([[Record ->> '$.Treatment.Surgery.ProcedureDate'], Record ->> '$.Treatment[*].Surgery.ProcedureDate'], recursive := true) as ProcedureDate,
unnest ([[Record ->> '$.Treatment.Surgery.PrimaryProcedureOpcs.@code'], Record ->> '$.Treatment[*].Surgery.PrimaryProcedureOpcs.@code'], recursive := true) as PrimaryProcedureOpcs from omop_staging.cosd_staging_901 where type = 'CT' ) select distinct NhsNumber, ProcedureDate, PrimaryProcedureOpcs from ct where NhsNumber is not null and PrimaryProcedureOpcs is not null;
